code = """import json
import re

# Read business hours data
business_hours_path = locals()['var_functions.query_db:4']
with open(business_hours_path, 'r') as f:
    businesses = json.load(f)

# Read review ratings data
ratings_data = locals()['var_functions.query_db:14']

# Create a dictionary for quick lookup of ratings by gmap_id
ratings_dict = {item['gmap_id']: float(item['avg_rating']) for item in ratings_data}

# Parse hours to find businesses open after 6:00 PM on weekdays
weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

def parse_time_to_minutes(time_str):
    if not time_str or time_str == 'Closed' or time_str == 'Open 24 hours':
        return None
    
    time_str = time_str.strip()
    
    if 'AM' in time_str or 'PM' in time_str:
        if 'AM' in time_str:
            period = 'AM'
            time_str = time_str.replace('AM', '')
        else:
            period = 'PM'
            time_str = time_str.replace('PM', '')
        
        if ':' in time_str:
            hours, minutes = map(int, time_str.split(':'))
        else:
            hours = int(time_str)
            minutes = 0
        
        if period == 'PM' and hours != 12:
            hours += 12
        elif period == 'AM' and hours == 12:
            hours = 0
        
        return hours * 60 + minutes
    
    return None

def is_open_after_6pm(hours_list):
    if not hours_list:
        return False
    
    try:
        if isinstance(hours_list, str):
            hours_data = eval(hours_list)
        else:
            hours_data = hours_list
            
        for day_info in hours_data:
            day = day_info[0]
            time_range = day_info[1]
            
            if day in weekdays:
                if time_range == 'Open 24 hours':
                    return True
                
                if time_range == 'Closed':
                    continue
                
                if u'\u2013' in time_range:
                    start_time, end_time = time_range.split(u'\u2013')
                elif '-' in time_range:
                    start_time, end_time = time_range.split('-')
                else:
                    continue
                
                end_minutes = parse_time_to_minutes(end_time)
                if end_minutes is not None and end_minutes > 1080:
                    return True
        
        return False
    except Exception as e:
        return False

# Filter businesses that are open after 6:00 PM on weekdays
open_after_6pm = []
for business in businesses:
    if is_open_after_6pm(business['hours']):
        gmap_id = business['gmap_id']
        avg_rating = ratings_dict.get(gmap_id, 0)
        if avg_rating > 0:  # Only include if there are reviews
            open_after_6pm.append({
                'gmap_id': gmap_id,
                'name': business['name'],
                'hours': business['hours'],
                'avg_rating': avg_rating
            })

# Sort by average rating (descending)
open_after_6pm_sorted = sorted(open_after_6pm, key=lambda x: x['avg_rating'], reverse=True)

# Get all businesses (not just top 5) to verify
print('__RESULT__:')
print(json.dumps({
    'total_businesses_open_after_6pm': len(open_after_6pm_sorted),
    'businesses_with_5_star': len([b for b in open_after_6pm_sorted if b['avg_rating'] == 5.0]),
    'top_10': open_after_6pm_sorted[:10]
}, indent=2))"""

